REMEDIATION_CODE_TERRAFORM:
```hcl
# Terraform: enable Bedrock data event logging on an actively logging trail
resource "aws_cloudtrail" "example_resource" {
  name           = "example_resource"
  s3_bucket_name = "example_resource"

  advanced_event_selector {
    name = "Bedrock data events"
    field_selector {
      field  = "eventCategory"
      equals = ["Data"]
    }
    field_selector {
      field  = "resources.type"                # CRITICAL: target Bedrock resources
      equals = ["AWS::Bedrock::Model", "AWS::Bedrock::Guardrail", "AWS::Bedrock::AgentAlias", "AWS::Bedrock::FlowAlias", "AWS::Bedrock::InlineAgent", "AWS::Bedrock::KnowledgeBase", "AWS::Bedrock::Prompt"]
    }
  }
}
```

```hcl
# Terraform: enable multi-region and log management events (read & write)
resource "aws_cloudtrail" "<example_resource_name>" {
  name           = "<example_resource_name>"
  s3_bucket_name = "<example_resource_name>"

  is_multi_region_trail = true  # CRITICAL: apply the trail to all regions

  event_selector {
    include_management_events = true  # CRITICAL: log management events
    read_write_type           = "All" # CRITICAL: log both read & write
  }
}
```

